<script>var cursor=document.getElementById('cursor'),ring=document.getElementById('cursorRing'),mx=0,my=0,rx=0,ry=0;
document.addEventListener('mousemove',function(e){mx=e.clientX;my=e.clientY;cursor.style.left=mx+'px';cursor.style.top=my+'px';});
function animateRing(){rx+=(mx-rx)*.12;ry+=(my-ry)*.12;ring.style.left=rx+'px';ring.style.top=ry+'px';requestAnimationFrame(animateRing);}
animateRing();
document.querySelectorAll('a,button').forEach(function(el){el.addEventListener('mouseenter',function(){cursor.style.transform='translate(-50%,-50%) scale(2.5)';ring.style.width='48px';ring.style.height='48px';});el.addEventListener('mouseleave',function(){cursor.style.transform='translate(-50%,-50%) scale(1)';ring.style.width='32px';ring.style.height='32px';});});
var reveals=document.querySelectorAll('.reveal');
var obs=new IntersectionObserver(function(entries){entries.forEach(function(e,i){if(e.isIntersecting){setTimeout(function(){e.target.classList.add('visible');},i*80);obs.unobserve(e.target);}});},{threshold:.1,rootMargin:'0px 0px -60px 0px'});
reveals.forEach(function(el){obs.observe(el);});
document.querySelectorAll('.faq-question').forEach(function(q){q.addEventListener('click',function(){var item=q.parentElement,isOpen=item.classList.contains('open');document.querySelectorAll('.faq-item').forEach(function(i){i.classList.remove('open');});if(!isOpen)item.classList.add('open');});});
  // Esconde pré-visualização de URL no canto do navegador sem afetar funcionalidade
  document.querySelectorAll('a').forEach(function(a) {
    var href = a.getAttribute('href');
    if (!href) return;
    a.setAttribute('data-href', href);
    a.removeAttribute('href');
    a.style.cursor = 'pointer';
    a.addEventListener('click', function(e) {
      e.preventDefault();
      var target = a.getAttribute('target');
      var url = a.getAttribute('data-href');
      if (target === '_blank') { window.open(url, '_blank'); }
      else { window.location.href = url; }
    });
  });
</script>
